import React, { useState } from "react";
import ListaDisciplinas from "../ListaDisciplinas";
import FormDisciplina from "../FormDisciplina";
import Modal from "./Modal";

export default function TelaDisciplinas() {
  const [mostrarModal, setMostrarModal] = useState(false);
  const [editando, setEditando] = useState(null);
  const [reloadKey, setReloadKey] = useState(0);

  const handleNovo = () => {
    setEditando(null);
    setMostrarModal(true);
  };

  const handleEditar = (disciplina) => {
    setEditando(disciplina);
    setMostrarModal(true);
  };

  const handleSalvar = () => {
    setMostrarModal(false);
    setEditando(null);
    setReloadKey((k) => k + 1);
  };

  const handleCancelar = () => {
    setMostrarModal(false);
    setEditando(null);
  };

  return (
    <div className="bg-white p-6 rounded-2xl shadow-lg max-w-4xl mx-auto">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold text-[#1d3557] tracking-tight">Disciplinas</h1>
        <button
          onClick={handleNovo}
          className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-xl font-medium shadow transition"
        >
          Nova Disciplina
        </button>
      </div>
      <ListaDisciplinas reloadKey={reloadKey} onEditar={handleEditar} />
      <Modal isOpen={mostrarModal} onRequestClose={handleCancelar}>
        <FormDisciplina
          onNovaDisciplina={handleSalvar}
          disciplinaEditando={editando}
          onFimEdicao={handleCancelar}
        />
      </Modal>
    </div>
  );
}
